def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    if not nums:
        return True
    return all(nums[i] + nums[j] != target for i in range(len(nums)) for j in range(i + 1, len(nums)))

def check_indices_not_reused(left, right):
    return left != right

# Unit tests for critical behaviors
def test_solve():
    assert solve([1, 2, 3, 4, 5], 9) == (3, 4)
    assert solve([1, 2, 3, 4, 5], 10) == -1, -1
    assert solve([], 5) == -1, -1
    assert solve([1, 2, 3, 4, 5], 0) == -1, -1

# Adversarial/edge-case tests
def test_edge_cases():
    assert solve([1, 1, 1, 1], 2) == (0, 1)
    assert solve([1, 2, 3, 4, 5], 6) == (0, 3)
    assert solve([5, 5, 5, 5], 10) == (0, 1)

# Run tests
test_solve()
test_edge_cases()
